  1→import { CronExpressionParser } from "cron-parser";
  2→import {
  3→  createTaskExtended,
  4→  getDb,
  5→  getDueScheduledTasks,
  6→  getScheduledTaskById,
  7→  updateScheduledTask,
  8→} from "@/be/db";
  9→import type { ScheduledTask } from "@/types";
 10→
 11→let schedulerInterval: ReturnType<typeof setInterval> | null = null;
 12→let isProcessing = false;
 13→
 14→/**
 15→ * Recover missed scheduled task runs from downtime.
 16→ * Fires ONE catch-up run per schedule (not N missed runs).
 17→ * Tags the task with "recovered" so it's distinguishable.
 18→ */
 19→async function recoverMissedSchedules(): Promise<void> {
 20→  const now = new Date();
 21→  const dueSchedules = getDueScheduledTasks();
 22→
 23→  for (const schedule of dueSchedules) {
 24→    if (!schedule.nextRunAt) continue;
 25→    const missedBy = now.getTime() - new Date(schedule.nextRunAt).getTime();
 26→    if (missedBy < 15000) continue; // Less than 15s — normal timing jitter
 27→
 28→    console.log(
 29→      `[Scheduler] Recovering missed schedule "${schedule.name}" ` +
 30→        `(was due ${Math.round(missedBy / 1000)}s ago)`,
 31→    );
 32→
 33→    try {
 34→      const tx = getDb().transaction(() => {
 35→        createTaskExtended(schedule.taskTemplate, {
 36→          creatorAgentId: schedule.createdByAgentId,
 37→          taskType: schedule.taskType,
 38→          tags: [...schedule.tags, "scheduled", `schedule:${schedule.name}`, "recovered"],
 39→          priority: schedule.priority,
 40→          agentId: schedule.targetAgentId,
 41→          model: schedule.model,
 42→          scheduleId: schedule.id,
 43→          source: "schedule",
 44→        });
 45→
 46→        const nextRun = calculateNextRun(schedule, now);
 47→        updateScheduledTask(schedule.id, {
 48→          lastRunAt: now.toISOString(),
 49→          nextRunAt: nextRun,
 50→          lastUpdatedAt: now.toISOString(),
 51→        });
 52→      });
 53→      tx();
 54→    } catch (err) {
 55→      console.error(`[Scheduler] Error recovering "${schedule.name}":`, err);
 56→    }
 57→  }
 58→}
 59→
 60→/**
 61→ * Calculate next run time based on cron expression or interval.
 62→ * @param schedule The scheduled task
 63→ * @param fromTime The time to calculate from (defaults to now)
 64→ * @returns ISO string of next run time
 65→ */
 66→export function calculateNextRun(schedule: ScheduledTask, fromTime: Date = new Date()): string {
 67→  if (schedule.cronExpression) {
 68→    const interval = CronExpressionParser.parse(schedule.cronExpression, {
 69→      currentDate: fromTime,
 70→      tz: schedule.timezone || "UTC",
 71→    });
 72→    const nextDate = interval.next();
 73→    const isoString = nextDate.toISOString();
 74→    if (!isoString) {
 75→      throw new Error("Failed to calculate next run time from cron expression");
 76→    }
 77→    return isoString;
 78→  }
 79→
 80→  if (schedule.intervalMs) {
 81→    return new Date(fromTime.getTime() + schedule.intervalMs).toISOString();
 82→  }
 83→
 84→  throw new Error("Schedule must have cronExpression or intervalMs");
 85→}
 86→
 87→// Exponential backoff schedule for consecutive errors (in ms)
 88→const ERROR_BACKOFF_MS = [
 89→  60_000, // 1 minute
 90→  300_000, // 5 minutes
 91→  900_000, // 15 minutes
 92→  1_800_000, // 30 minutes
 93→  3_600_000, // 1 hour (cap)
 94→];
 95→
 96→const MAX_CONSECUTIVE_ERRORS = 5;
 97→
 98→function getBackoffMs(consecutiveErrors: number): number {
 99→  const idx = Math.min(consecutiveErrors - 1, ERROR_BACKOFF_MS.length - 1);
100→  return ERROR_BACKOFF_MS[Math.max(0, idx)] ?? ERROR_BACKOFF_MS[0]!;
101→}
102→
103→/**
104→ * Execute a single scheduled task by creating an agent task.
105→ * Tracks consecutive errors and applies exponential backoff on failure.
106→ */
107→async function executeSchedule(schedule: ScheduledTask): Promise<void> {
108→  try {
109→    const tx = getDb().transaction(() => {
110→      const now = new Date().toISOString();
111→
112→      createTaskExtended(schedule.taskTemplate, {
113→        creatorAgentId: schedule.createdByAgentId,
114→        taskType: schedule.taskType,
115→        tags: [...schedule.tags, "scheduled", `schedule:${schedule.name}`],
116→        priority: schedule.priority,
117→        agentId: schedule.targetAgentId,
118→        model: schedule.model,
119→        scheduleId: schedule.id,
120→        source: "schedule",
121→      });
122→
123→      const nextRun = calculateNextRun(schedule, new Date());
124→      updateScheduledTask(schedule.id, {
125→        lastRunAt: now,
126→        nextRunAt: nextRun,
127→        lastUpdatedAt: now,
128→        // Reset error tracking on success
129→        consecutiveErrors: 0,
130→        lastErrorAt: null,
131→        lastErrorMessage: null,
132→      });
133→
134→      return nextRun;
135→    });
136→
137→    const nextRun = tx();
138→    console.log(`[Scheduler] Executed schedule "${schedule.name}", next run: ${nextRun}`);
139→  } catch (err) {
140→    const errorCount = (schedule.consecutiveErrors ?? 0) + 1;
141→    const now = new Date();
142→    const errorMsg = err instanceof Error ? err.message : String(err);
143→
144→    console.error(
145→      `[Scheduler] Error executing "${schedule.name}" (${errorCount} consecutive):`,
146→      errorMsg,
147→    );
148→
149→    const updates: {
150→      consecutiveErrors: number;
151→      lastErrorAt: string;
152→      lastErrorMessage: string;
153→      lastUpdatedAt: string;
154→      enabled?: boolean;
155→      nextRunAt?: string;
156→    } = {
157→      consecutiveErrors: errorCount,
158→      lastErrorAt: now.toISOString(),
159→      lastErrorMessage: errorMsg.slice(0, 500),
160→      lastUpdatedAt: now.toISOString(),
161→    };
162→
163→    if (errorCount >= MAX_CONSECUTIVE_ERRORS) {
164→      updates.enabled = false;
165→      console.warn(
166→        `[Scheduler] Auto-disabled "${schedule.name}" after ${errorCount} consecutive errors`,
167→      );
168→    } else {
169→      const backoff = getBackoffMs(errorCount);
170→      updates.nextRunAt = new Date(now.getTime() + backoff).toISOString();
171→      console.log(`[Scheduler] Backing off "${schedule.name}" for ${backoff / 1000}s`);
172→    }
173→
174→    updateScheduledTask(schedule.id, updates);
175→  }
176→}
177→
178→/**
179→ * Start the scheduler polling loop.
180→ * @param intervalMs Polling interval in milliseconds (default: 10000)
181→ */
182→export function startScheduler(intervalMs = 10000): void {
183→  if (schedulerInterval) {
184→    console.log("[Scheduler] Already running");
185→    return;
186→  }
187→
188→  console.log(`[Scheduler] Starting with ${intervalMs}ms polling interval`);
189→
190→  // Recover missed schedules from downtime, then run normal processing
191→  void recoverMissedSchedules().then(() => processSchedules());
192→
193→  schedulerInterval = setInterval(async () => {
194→    await processSchedules();
195→  }, intervalMs);
196→}
197→
198→/**
199→ * Process all due schedules (called by interval).
200→ */
201→async function processSchedules(): Promise<void> {
202→  if (isProcessing) return;
203→  isProcessing = true;
204→
205→  try {
206→    const dueSchedules = getDueScheduledTasks();
207→
208→    for (const schedule of dueSchedules) {
209→      try {
210→        await executeSchedule(schedule);
211→      } catch (err) {
212→        console.error(`[Scheduler] Error executing "${schedule.name}":`, err);
213→      }
214→    }
215→  } finally {
216→    isProcessing = false;
217→  }
218→}
219→
220→/**
221→ * Stop the scheduler polling loop.
222→ */
223→export function stopScheduler(): void {
224→  if (schedulerInterval) {
225→    clearInterval(schedulerInterval);
226→    schedulerInterval = null;
227→    isProcessing = false;
228→    console.log("[Scheduler] Stopped");
229→  }
230→}
231→
232→/**
233→ * Run a schedule immediately (manual trigger).
234→ * Does NOT update nextRunAt - the regular schedule continues unaffected.
235→ * @param scheduleId The ID of the schedule to run
236→ */
237→export async function runScheduleNow(scheduleId: string): Promise<void> {
238→  const schedule = getScheduledTaskById(scheduleId);
239→  if (!schedule) {
240→    throw new Error(`Schedule not found: ${scheduleId}`);
241→  }
242→  if (!schedule.enabled) {
243→    throw new Error(`Schedule is disabled: ${schedule.name}`);
244→  }
245→
246→  // Wrap in transaction to ensure atomicity of task creation and schedule update
247→  const tx = getDb().transaction(() => {
248→    const now = new Date().toISOString();
249→
250→    // Create the actual task
251→    createTaskExtended(schedule.taskTemplate, {
252→      creatorAgentId: schedule.createdByAgentId,
253→      taskType: schedule.taskType,
254→      tags: [...schedule.tags, "scheduled", `schedule:${schedule.name}`, "manual-run"],
255→      priority: schedule.priority,
256→      agentId: schedule.targetAgentId,
257→      model: schedule.model,
258→      scheduleId: schedule.id,
259→      source: "schedule",
260→    });
261→
262→    // Only update lastRunAt, not nextRunAt (to not affect regular schedule)
263→    updateScheduledTask(schedule.id, {
264→      lastRunAt: now,
265→      lastUpdatedAt: now,
266→    });
267→  });
268→
269→  tx();
270→
271→  console.log(`[Scheduler] Manually executed schedule "${schedule.name}"`);
272→}
