  1→import type { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
  2→import { CronExpressionParser } from "cron-parser";
  3→import * as z from "zod";
  4→import {
  5→  getAgentById,
  6→  getScheduledTaskById,
  7→  getScheduledTaskByName,
  8→  updateScheduledTask,
  9→} from "@/be/db";
 10→import { calculateNextRun } from "@/scheduler";
 11→import { createToolRegistrar } from "@/tools/utils";
 12→
 13→export const registerUpdateScheduleTool = (server: McpServer) => {
 14→  createToolRegistrar(server)(
 15→    "update-schedule",
 16→    {
 17→      title: "Update Scheduled Task",
 18→      annotations: { idempotentHint: true },
 19→      description:
 20→        "Update an existing scheduled task. Only the creator or lead agent can update schedules.",
 21→      inputSchema: z.object({
 22→        scheduleId: z.string().uuid().optional().describe("Schedule ID to update"),
 23→        name: z.string().optional().describe("Schedule name to update (alternative to ID)"),
 24→        newName: z.string().min(1).max(100).optional().describe("New name for the schedule"),
 25→        taskTemplate: z.string().min(1).optional().describe("New task template"),
 26→        cronExpression: z.string().optional().describe("New cron expression"),
 27→        intervalMs: z.number().int().positive().optional().describe("New interval in milliseconds"),
 28→        description: z.string().optional().describe("New description"),
 29→        taskType: z.string().max(50).optional().describe("New task type"),
 30→        tags: z.array(z.string()).optional().describe("New tags"),
 31→        priority: z.number().int().min(0).max(100).optional().describe("New priority"),
 32→        targetAgentId: z.string().uuid().nullable().optional().describe("New target agent ID"),
 33→        timezone: z.string().optional().describe("New timezone"),
 34→        enabled: z.boolean().optional().describe("Enable or disable the schedule"),
 35→        model: z
 36→          .enum(["haiku", "sonnet", "opus"])
 37→          .nullable()
 38→          .optional()
 39→          .describe("Model to use for tasks created by this schedule. Set to null to clear."),
 40→      }),
 41→      outputSchema: z.object({
 42→        yourAgentId: z.string().uuid().optional(),
 43→        success: z.boolean(),
 44→        message: z.string(),
 45→        schedule: z
 46→          .object({
 47→            id: z.string(),
 48→            name: z.string(),
 49→            description: z.string().optional(),
 50→            cronExpression: z.string().optional(),
 51→            intervalMs: z.number().optional(),
 52→            taskTemplate: z.string(),
 53→            taskType: z.string().optional(),
 54→            tags: z.array(z.string()),
 55→            priority: z.number(),
 56→            targetAgentId: z.string().optional(),
 57→            enabled: z.boolean(),
 58→            lastRunAt: z.string().optional(),
 59→            nextRunAt: z.string().optional(),
 60→            createdByAgentId: z.string().optional(),
 61→            timezone: z.string(),
 62→            model: z.string().optional(),
 63→            createdAt: z.string(),
 64→            lastUpdatedAt: z.string(),
 65→          })
 66→          .optional(),
 67→      }),
 68→    },
 69→    async (
 70→      {
 71→        scheduleId,
 72→        name,
 73→        newName,
 74→        taskTemplate,
 75→        cronExpression,
 76→        intervalMs,
 77→        description,
 78→        taskType,
 79→        tags,
 80→        priority,
 81→        targetAgentId,
 82→        timezone,
 83→        enabled,
 84→        model,
 85→      },
 86→      requestInfo,
 87→      _meta,
 88→    ) => {
 89→      if (!requestInfo.agentId) {
 90→        return {
 91→          content: [{ type: "text", text: 'Agent ID not found. Set the "X-Agent-ID" header.' }],
 92→          structuredContent: {
 93→            success: false,
 94→            message: 'Agent ID not found. Set the "X-Agent-ID" header.',
 95→          },
 96→        };
 97→      }
 98→
 99→      // Find the schedule
100→      const schedule = scheduleId
101→        ? getScheduledTaskById(scheduleId)
102→        : name
103→          ? getScheduledTaskByName(name)
104→          : null;
105→
106→      if (!schedule) {
107→        return {
108→          content: [{ type: "text", text: "Schedule not found." }],
109→          structuredContent: {
110→            success: false,
111→            message: "Schedule not found.",
112→          },
113→        };
114→      }
115→
