 31→function formatInterval(ms: number): string {
 32→  const seconds = ms / 1000;
 33→  if (seconds < 60) return `${seconds}s`;
 34→  const minutes = seconds / 60;
 35→  if (minutes < 60) return `${minutes}m`;
 36→  const hours = minutes / 60;
 37→  if (hours < 24) return `${hours}h`;
 38→  return `${hours / 24}d`;
 39→}
