const headers = { "Authorization": "Bearer 123123", "Content-Type": "application/json" };

async function api(method, path, body) {
  const res = await fetch(`${BASE}${path}`, {
    method,
    headers,
    body: body ? JSON.stringify(body) : undefined,
  });
  const data = await res.json();
  return { status: res.status, data };
}

// 1. Create one-time with delayMs
const r1 = await api("POST", "/api/schedules", {
  name: "test-one-time-delay",
  taskTemplate: "Say hello - one-time test",
  scheduleType: "one_time",
  delayMs: 30000,
});
console.log("=== Create one-time (delayMs) ===");
console.log(`Status: ${r1.status}, scheduleType: ${r1.data.scheduleType}, nextRunAt: ${r1.data.nextRunAt}`);

