const runAt = new Date(Date.now() + 60000).toISOString();
const r2 = await api("POST", "/api/schedules", {
  name: "test-one-time-runat",
  taskTemplate: "RunAt test",
  scheduleType: "one_time",
  runAt,
});
console.log("\n=== Create one-time (runAt) ===");
console.log(`Status: ${r2.status}, scheduleType: ${r2.data.scheduleType}, nextRunAt: ${r2.data.nextRunAt}`);

