const r3 = await api("POST", "/api/schedules", {
  name: "bad",
  taskTemplate: "bad",
  scheduleType: "one_time",
  cronExpression: "* * * * *",
});
console.log("\n=== Should fail: one_time + cron ===");
console.log(`Status: ${r3.status}, error: ${r3.data.error}`);

