const BASE = "http://localhost:3013";
const headers = { "Authorization": "Bearer 123123", "Content-Type": "application/json" };

async function api(method, path, body) {
  const res = await fetch(`${BASE}${path}`, { method, headers, body: body ? JSON.stringify(body) : undefined });
  return { status: res.status, data: await res.json() };
}

// Get the one-time schedule ID
const list = await api("GET", "/api/scheduled-tasks?hideCompleted=false");
const oneTime = list.data.scheduledTasks.find(s => s.name === "test-one-time-delay");
console.log(`Schedule: ${oneTime.name}, id: ${oneTime.id}, enabled: ${oneTime.enabled}`);

// Run it manually
const run = await api("POST", `/api/schedules/${oneTime.id}/run`);
console.log(`\nRun result status: ${run.status}`);

// Check it's now disabled
const after = await api("GET", `/api/schedules/${oneTime.id}`);
console.log(`\nAfter run:`);
console.log(`  enabled: ${after.data.enabled}`);
console.log(`  lastRunAt: ${after.data.lastRunAt}`);
console.log(`  nextRunAt: ${after.data.nextRunAt}`);
console.log(`  scheduleType: ${after.data.scheduleType}`);

// Verify it's hidden from default list
const defaultList = await api("GET", "/api/scheduled-tasks");
const hidden = defaultList.data.scheduledTasks.find(s => s.name === "test-one-time-delay");
console.log(`\nHidden from default list: ${hidden === undefined}`);

// But visible with hideCompleted=false
const fullList = await api("GET", "/api/scheduled-tasks?hideCompleted=false");
const visible = fullList.data.scheduledTasks.find(s => s.name === "test-one-time-delay");
console.log(`Visible with hideCompleted=false: ${visible !== undefined}`);

// Verify rejected update on completed one-time
const updateRes = await api("PUT", `/api/schedules/${oneTime.id}`, { taskTemplate: "new template" });
console.log(`\nUpdate completed one-time: status=${updateRes.status}, error=${updateRes.data.error}`);

